link.script:
$.post("/eServices/Online/IsAuthenticated", function(data) {
    if (data != null && data.IsAuthenticated != null && data.IsAuthenticated == false) {
        $("body").hide();
        window.location = "/eServices/Online/Logout";
    }
});

var dataTableTexts = {
