    console = {
        log: function() {},
        error: function() {},
        trace: function() {},
        dir: function() {}
    };
}

var selectedCulture = "fi-FI";
var apiUrl = "https://minunenergia.fi/api/";
var userName = "";
var SessionTimeOutUrl = "/Default/IsSessionExpired";
var SessionTimeOutRedirectUrl = "/Default/SessionExpired";

function showErrorMessage(message) {
    $("#infoMessage").text(message);
    $("#infoArea").show();
}

$(function() {

    //This hides validation errors from fields
    $("form input").on("change keydown paste input", function(ev) {
        _notificator.hideValidationError(this);
    });

    var culture = 'fi-FI';

    Globalize.culture(culture);

    if ($.validator) {
        $.validator.methods.number = function(value, element) {
            if (Globalize.parseFloat(value)) {
                return true;
            }
            return false;
        }
    }

    userName = "samisaalasti";

});

