link.script:



    Kulutus yhteensä: ${consumption.toFixed(digits).replace('.',',')} ${unit}.



    {{if (HeatedFloorArea != null) }}
    Energiatehokkuus: ${(consumption/HeatedFloorArea).toFixed(digits).replace('.',',')} ${unit}/m2


    {{/if}}

    {{if ($item.enablePriceSeries && expenses) }}
    {{if (customerType != 1) }}
    Kustannukset yhteensä (ALV 0 %): ${expenses.toFixed(2).replace('.',',')} €
    {{else}}
    Kustannukset yhteensä: ${expenses.toFixed(2).replace('.',',')} €
    {{/if}}


    {{/if}}

    {{if prevConsumption}}
    Edellisen vuoden vastaavaan ajankohtaan verrattuna kulutuksenne on 
    {{tmpl( { diff: prevConsumption, unit: unit, digits: digits } ) "#comparisonTemplate"}}
    {{/if}}
    {{if nextConsumption}}
    Seuraavan vuoden vastaavaan ajankohtaan verrattuna kulutuksenne on 
    {{tmpl( { diff: nextConsumption, unit: unit, digits: digits } ) "#comparisonTemplate"}}
    {{/if}}


